function.body:
TYPE RECORD IS REF CURSOR;
	vRecord RECORD;
	vCashClosure RECORD;
	vSetup RECORD;
    vIncExp RECORD;

    vResult VARCHAR2(2000) := '';
	v_Result NUMBER:=1; -- 0=failure
	vRecordID VARCHAR2(32);
	vUserID VARCHAR2(32);
	v_Message VARCHAR2(2000):='';

	v_count NUMBER;

BEGIN

	--  Update AD_PInstance
	DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || pInstanceID) ;
	vResult := 'PInstanceNotFound';
    AD_UPDATE_PINSTANCE(pInstanceID, NULL, 'Y', NULL, NULL) ;

	BEGIN

		FOR vRecord IN (
			SELECT
				i.Record_ID,
				i.AD_User_ID,
				p.ParameterName,
				p.P_String,
				p.P_Number,
				p.P_Date,
				p.AD_Client_ID,
				p.AD_Org_ID,
				p.CreatedBy        
			FROM AD_PInstance AS i
				LEFT JOIN AD_PInstance_Para AS p ON i.AD_PInstance_ID = p.AD_PInstance_ID
			WHERE i.AD_PInstance_ID = pInstanceID
			ORDER BY p.SeqNo
      ) LOOP
			vRecordID := vRecord.Record_ID;
			vUserID := vRecord.AD_User_ID; 
		END LOOP;

		--Obtenemos el cierre de caja
		SELECT * INTO vCashClosure
		FROM sccc_cash_clousure
		WHERE sccc_cash_clousure_id=vRecordID;

		--sccc_preunprocess - PreUnprocess Extension Point
		SELECT count(*) INTO v_count
		FROM DUAL
		where exists (select 1 from ad_ep_procedures where ad_extension_points_id = 'CE70BAE42A0F43CDB0B2F096E4194969');
		IF (v_count=1) THEN
			DECLARE
				v_ep_instance VARCHAR2(32);
				v_extension_point_id VARCHAR2(32) := 'CE70BAE42A0F43CDB0B2F096E4194969';

			BEGIN
				v_ep_instance := get_uuid();
			 AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Record_ID',
				vRecordID, NULL, NULL, NULL, NULL, NULL, NULL);
			 AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'DocAction',
				vCashClosure.record, NULL, NULL, NULL, NULL, NULL, NULL);
			 AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'User',
				vUserID, NULL, NULL, NULL, NULL, NULL, NULL);
			 AD_EXTENSION_POINT_HANDLER(v_ep_instance, v_extension_point_id);
				SELECT p_number INTO v_Result
				FROM ad_ep_instance_para
				WHERE ad_ep_instance_id = v_ep_instance
				AND parametername LIKE 'Result';
				SELECT p_text INTO v_Message
				FROM ad_ep_instance_para
				WHERE ad_ep_instance_id = v_ep_instance
				AND parametername LIKE 'Message';

				DELETE FROM ad_ep_instance_para
				WHERE ad_ep_instance_id = v_ep_instance;
			END;
		END IF;

		DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || coalesce(v_Message,''));
        AD_UPDATE_PINSTANCE(pInstanceID, NULL, 'N', coalesce(v_Result,1), coalesce(v_Message, ''));

		RETURN;

	END;

	EXCEPTION
	WHEN OTHERS THEN
    vResult:= '@ERROR=' || SQLERRM;
    DBMS_OUTPUT.PUT_LINE(vResult);
	ROLLBACK;
    AD_UPDATE_PINSTANCE(pInstanceID, NULL, 'N', 0, vResult);
    RETURN;
END SSRE_PRELOADLINESREFUNDINV
